%[text] # RealTimeCOIN - scalar examples
%[text] Companion notebook: `md_examples.m` (the multi-dimensional cases).
%[text] ## Section 1 - Setup
%[text] Put the RealTimeCOIN class (repo root) and the coinviz package (this folder) on the path. Run this section once before the others.
% Locate the repo root by looking for its folders (@RealTimeCOIN and
% examples/+coinviz). We can't trust mfilename here: pressing "Run Section"
% in the MATLAB Editor executes a copy of the code from a temp folder, so
% mfilename('fullpath') points at that temp path, not this file.
here = fileparts(mfilename('fullpath'));
repoRoot = '';
for c = {here, fileparts(here), pwd, fileparts(pwd)}
    d = c{1};
    if ~isempty(d) && isfolder(fullfile(d, '@RealTimeCOIN')) ...
            && isfolder(fullfile(d, 'examples', '+coinviz'))
        repoRoot = d; break;
    end
end
if isempty(repoRoot)
    error(['Cannot locate the RealTimeCOIN repo. cd to the repo root ' ...
        '(the folder containing @RealTimeCOIN and examples/) and re-run this section.']);
end
addpath(repoRoot);                                % RealTimeCOIN class
addpath(fullfile(repoRoot, 'examples'));          % +coinviz package
fprintf('Paths added. RealTimeCOIN on path: %d\n', exist('RealTimeCOIN', 'class') == 8); %[output:28c33686]
%%
%[text] ## Section 2 - Bias inference on a short cue sequence
%[text] The smallest demo: a handful of cued trials with noisy scalar feedback. The model infers, per trial, a posterior over the latent state (via numerical integration of state\_probability) and a distribution over contexts.
rng(1);
coin = RealTimeCOIN('num_particles', 200, 'max_contexts', 5, 'infer_bias', true);

cues        = [1 1 2 2 1 3 1];
trueValues  = [0.2 0.2 0.5 0.5 0.2 -0.1 0.2];        % latent target per trial
feedbacks   = trueValues + coin.sigma_sensory_noise * randn(size(trueValues));

grid = linspace(-1.5, 1.5, 201);
T = numel(cues);
predMean = zeros(1, T);
for t = 1:T %[output:group:42d22ed7]
    coin.observe_q(cues(t));
    coin.observe_y(feedbacks(t));

    dens = coin.state_probability(grid);             % posterior state density on the grid
    a = trapz(grid, dens); if a > 0, dens = dens / a; end
    predMean(t) = trapz(grid, dens .* grid);         % posterior mean by integration

    probs = coin.context_responsibilities();         % containers.Map: context -> responsibility
    fprintf('Trial %d (cue %d): E[state]=% .3f, contexts={', t, cues(t), predMean(t)); %[output:18adddcf] %[output:756058c9] %[output:03a3c309] %[output:2f86e7a7] %[output:9939b06e] %[output:99942c39] %[output:5f539235]
    kk = cell2mat(probs.keys);
    for k = kk, fprintf(' %d:%.2f', k, probs(k)); end %[output:8515fea6] %[output:4adfc767] %[output:877ae094] %[output:2521638b] %[output:7b8778f8] %[output:09e5b129] %[output:40aabbd0]
    fprintf(' }\n'); %[output:0f12add5] %[output:23b1ab34] %[output:405fc7b8] %[output:14f2b0bc] %[output:8ebc87ac] %[output:8cdee5b9] %[output:241f5059]
end %[output:group:42d22ed7]
fprintf('Final trial count (Trial property): %d\n', coin.Trial); %[output:1a3f0fef]

coinviz.stateTrace(1:T, feedbacks, trueValues, predMean, [], ... %[output:group:96a9bdf0] %[output:34f60eed]
    'FigName', 'Scalar: short cue sequence', 'PredictedName', 'Posterior mean'); %[output:group:96a9bdf0] %[output:34f60eed]
%%
%[text] ## Section 3 - Long run with missing observations
%[text] A 340-trial perturbation schedule that mirrors the original COIN tests: a baseline, a positive block, a short negative block, then a long stretch of **missing** feedback (NaN), which the model must coast through on its dynamics prior alone. The final figure shows the per-context posterior state density.
rng(3);
coin = RealTimeCOIN();                               % defaults (scalar)

truePert = [zeros(1,50), ones(1,125), -ones(1,15), NaN(1,150)];
obs = truePert + coin.sigma_sensory_noise * randn(size(truePert));

T = numel(obs);
ctxWidth = coin.max_contexts + 1;
predMean = zeros(1, T);
postCtx  = zeros(T, ctxWidth);
grid = linspace(-1.5, 1.5, 201);
for t = 1:T
    coin.observe_y(obs(t));                     % NaN = missing observation
    p = coin.context_responsibilities_local();        % fast local responsibilities
    postCtx(t, 1:numel(p)) = p;
    dens = coin.state_probability(grid);
    a = trapz(grid, dens); if a > 0, dens = dens / a; end
    predMean(t) = trapz(grid, dens .* grid);
end

coinviz.stateTrace(1:T, obs, truePert, predMean, [], ... %[output:group:2209228f] %[output:11ce2822]
    'FigName', 'Scalar: long run (missing obs)', 'PredictedName', 'Posterior mean'); %[output:group:2209228f] %[output:11ce2822]
coinviz.contextBars([], postCtx, 'FigName', 'Scalar: context responsibilities', ... %[output:group:5a9ec64e] %[output:3b7c8ea5]
    'PostTitle', 'Local/modal context responsibilities'); %[output:group:5a9ec64e] %[output:3b7c8ea5]

stateByCtx = coin.state_given_context_probability(grid);   % Map: context -> density
coinviz.densityLines(grid, stateByCtx, 'FigName', 'Scalar: per-context state density', ... %[output:group:99c176d6] %[output:98f22dc7]
    'Title', 'Final posterior state density given aligned context', 'XLabel', 'State value'); %[output:group:99c176d6] %[output:98f22dc7]
%%
%[text] ## Section 4 - Tuned "coin-rl" settings with cues
%[text] Same idea as Section 3 but with custom noise/retention priors (the settings used by the coin-rl tests) and an explicit cue stream, so we can compare the **predicted** context probabilities (before each observation) against the **responsibilities** (after).
rng(3);
priorMeanRetention = 0.9425;
coin = RealTimeCOIN('sigma_sensory_noise', 0.03, 'sigma_motor_noise', 0.0182, ...
    'prior_mean_retention', priorMeanRetention, ...
    'prior_precision_drift', 1 / (0.0001 + (1 - priorMeanRetention^2)));

blockPert = [0, 0.5, -0.5, 0.5];         % target per block
blockCues = [1, 2, 3, 2];                % cue per block
blockLen  = 80;
truePert = repelem(blockPert, blockLen);
cues     = repelem(blockCues, blockLen);
obs = truePert + coin.sigma_sensory_noise * randn(size(truePert));

T = numel(obs);
ctxWidth = coin.max_contexts + 1;
predMean = zeros(1, T);
prevCtx  = zeros(T, ctxWidth);
postCtx  = zeros(T, ctxWidth);
grid = linspace(-1.5, 1.5, 201);
for t = 1:T
    coin.observe_q(cues(t));
    pv = coin.predicted_context_probabilities_local();
    prevCtx(t, 1:numel(pv)) = pv;

    coin.observe_y(obs(t));
    rv = coin.context_responsibilities_local();
    postCtx(t, 1:numel(rv)) = rv;

    dens = coin.state_probability(grid);
    a = trapz(grid, dens); if a > 0, dens = dens / a; end
    predMean(t) = trapz(grid, dens .* grid);
end
blockEdges = blockLen * (1:numel(blockCues)-1);

coinviz.stateTrace(1:T, obs, truePert, predMean, blockEdges, ... %[output:group:956e5765] %[output:664e4ea3]
    'FigName', 'Scalar: tuned settings', 'PredictedName', 'Posterior mean'); %[output:group:956e5765] %[output:664e4ea3]
coinviz.contextBars(prevCtx, postCtx, 'FigName', 'Scalar: predicted vs responsibilities'); %[output:8dc4565b]
coinviz.densityLines(grid, coin.state_given_context_probability(grid), ... %[output:group:91a30e30] %[output:1538f60b]
    'FigName', 'Scalar: per-context state density (tuned)', ... %[output:1538f60b]
    'Title', 'Per-context state density', 'XLabel', 'State value'); %[output:group:91a30e30] %[output:1538f60b]
%%
%[text] ## Section 5 - Save, load and stationarize
%[text] saveModel serializes a trained model to a .mat file; loadModel restores it into a fresh object. With setStationary = true the saved model is first put into its steady state (Trial reset to 0, context probabilities set to the stationary distribution) so it can be reused as a prior. set\_stationary does that in place. Here we verify a load round-trip reproduces the responsibilities.
rng(4);
coin = RealTimeCOIN('infer_bias', true);
cueSeq = [1 1 2 2 1 2 1 2];
valSeq = [0.2 0.2 -0.3 -0.3 0.2 -0.3 0.2 -0.3];
for t = 1:numel(cueSeq)
    coin.observe_q(cueSeq(t));
    coin.observe_y(valSeq(t) + coin.sigma_sensory_noise * randn);
end
fprintf('Before save: Trial = %d, active contexts = %d\n', coin.Trial, coin.context_responsibilities().Count); %[output:855e6bdc]

tmpFile = [tempname '.mat'];

% (a) Non-stationary save preserves the live trial state exactly.
coin.saveModel(tmpFile, false);
reloaded = RealTimeCOIN('infer_bias', true);
reloaded.loadModel(tmpFile);
r1 = coin.context_responsibilities();
r2 = reloaded.context_responsibilities();
maxDiff = max(abs(cell2mat(r1.values) - cell2mat(r2.values)));
fprintf('Non-stationary reload: Trial = %d, max responsibility diff = %.2e\n', ... %[output:group:4650d0c1] %[output:13b0d315]
    reloaded.Trial, maxDiff); %[output:group:4650d0c1] %[output:13b0d315]

% (b) Stationary save resets Trial while retaining learned contexts.
coin.saveModel(tmpFile, true);
stationaryModel = RealTimeCOIN('infer_bias', true);
stationaryModel.loadModel(tmpFile);
fprintf('Stationary reload:     Trial = %d (reset), active contexts = %d (retained)\n', ... %[output:group:192a6563] %[output:2cd7233b]
    stationaryModel.Trial, stationaryModel.context_responsibilities().Count); %[output:group:192a6563] %[output:2cd7233b]

% (c) set_stationary applied in place to a copy trained the same way. It drives
%     the model onto the stationary distribution of its own learned context
%     transition matrix, so the analytic stationary_context_probabilities
%     computed *before* the reset matches the distribution the model actually
%     adopts *after* it (over the instantiated contexts).
piAnalytic = coin.stationary_context_probabilities();   % 1-by-K analytic stationary
coin.set_stationary();
fprintf('After set_stationary:  Trial = %d\n', coin.Trial); %[output:6cff421a]

predicted = coin.predicted_context_probabilities();     % 1-by-(max_contexts+1)
resp      = coin.responsibilities();
Kk        = numel(piAnalytic);
predKnown = predicted(1:Kk) / sum(predicted(1:Kk));     % drop the novel slot, renormalise
fprintf('stationary_context_probabilities (analytic) : [%s]\n', num2str(piAnalytic, '%.3f ')); %[output:3e33a5c5]
fprintf('predicted context probs after (known/renorm): [%s]\n', num2str(predKnown, '%.3f ')); %[output:311f2768]
fprintf('max|analytic - adopted| = %.3f\n', max(abs(piAnalytic - predKnown))); %[output:932ad678]
% After the reset the chain sits at its fixed point, so predicted == responsibilities.
assert(max(abs(predicted(:) - resp(:))) < 1e-9, ...
    'predicted == responsibilities after set_stationary');
assert(max(abs(piAnalytic - predKnown)) < 0.1, ...
    'model settles onto its analytic stationary distribution');
delete(tmpFile);
%%
%[text] ## Section 6 - Method coverage (remaining scalar API)
%[text] This section deliberately calls every public method not already exercised above, so the notebook demonstrates the full scalar API surface. It trains a short model and then queries it every which way, printing a checklist.
rng(5);
coin = RealTimeCOIN('infer_bias', true);
cueSeq = [1 1 2 2 1 3 1 2 3 1];
valSeq = [0.2 0.2 -0.3 -0.3 0.2 0.6 0.2 -0.3 0.6 0.2];
for t = 1:numel(cueSeq)
    coin.observe_q(cueSeq(t));
    coin.observe_y(valSeq(t) + coin.sigma_sensory_noise * randn);
end
grid = linspace(-1.5, 1.5, 201);

fprintf('\n================ Scalar method coverage ================\n'); %[output:6c9b9e6c]
[mS, vS] = coin.state_moments();
fprintf('state_moments ................ mean % .3f, var %.4f\n', mS, vS); %[output:02d5fa0c]
fprintf('motor_output ................. % .3f\n', coin.motor_output()); %[output:673331bb]
fprintf('predictive_motor_output(1) ... % .3f\n', coin.predictive_motor_output(1)); %[output:82a2f1c2]
[mF, vF] = coin.predictive_feedback_moments(1);
fprintf('predictive_feedback_moments(1) mean % .3f, var %.4f\n', mF, vF); %[output:2e7afecc]
fprintf('predictive_state_feedback_cdf(0.2) . %.3f\n', coin.predictive_state_feedback_cdf(0.2, 1)); %[output:32c19edb]
fprintf('predictive_cue_p_value(1, 0.5) ..... %.3f\n', coin.predictive_cue_p_value(1, 0.5)); %[output:2e240ffc]

% Grid densities (feedback space and per-context feedback space).
fbDens = coin.state_feedback_probability(grid);
fprintf('state_feedback_probability ... integral %.3f\n', trapz(grid, fbDens)); %[output:7550e67c]
coinviz.densityLines(grid, coin.state_feedback_given_context_probability(grid), ... %[output:group:127bd4bb] %[output:1f775686]
    'FigName', 'Scalar: per-context feedback density', ... %[output:1f775686]
    'Title', 'state\_feedback\_given\_context\_probability', 'XLabel', 'Feedback', ... %[output:1f775686]
    'NovelDensity', coin.novel_state_feedback_probability(grid)); %[output:group:127bd4bb] %[output:1f775686]

% Novel (not-yet-instantiated) context densities overlaid on the state density.
coinviz.densityLines(grid, coin.state_given_context_probability(grid), ... %[output:group:7df192e8] %[output:003c29fa]
    'FigName', 'Scalar: state density + novel context', ... %[output:003c29fa]
    'Title', 'state\_given\_context\_probability with novel overlay', 'XLabel', 'State value', ... %[output:003c29fa]
    'NovelDensity', coin.novel_state_probability(grid)); %[output:group:7df192e8] %[output:003c29fa]

% Context summaries: global Maps, global vectors, and the alignment struct.
cpm = coin.context_predicted_probabilities();     % Map
crm = coin.context_responsibilities();            % Map
fprintf('context_predicted_probabilities .. %d contexts\n', cpm.Count); %[output:369470ed]
fprintf('context_responsibilities ......... %d contexts\n', crm.Count); %[output:31d38a67]
fprintf('predicted_context_probabilities .. [%s]\n', num2str(coin.predicted_context_probabilities(), '%.2f ')); %[output:91d669f2]
fprintf('responsibilities ................. [%s]\n', num2str(coin.responsibilities(), '%.2f ')); %[output:772aff7a]
fprintf('sampled_context_count ............ [%s]\n', num2str(coin.sampled_context_count(), '%.2f ')); %[output:5d78ed11]
fprintf('sampled_context_count_local ...... [%s]\n', num2str(coin.sampled_context_count_local(), '%.2f ')); %[output:1e6863f6]
al = coin.context_alignment();
fprintf('context_alignment ................ struct with fields: %s\n', strjoin(fieldnames(al)', ', ')); %[output:91b3748e]

% Per-trial c*/component scalars (the COIN "single most likely context" traces).
fprintf('explicit_component ........... % .3f\n', coin.explicit_component()); %[output:7d5ea2b4]
fprintf('implicit_component ........... % .3f\n', coin.implicit_component()); %[output:1e9bdf45]
fprintf('state_cstar1/2/3 ............. % .3f / % .3f / % .3f\n', ... %[output:group:16ecb7c6] %[output:6744c410]
    coin.state_cstar1(), coin.state_cstar2(), coin.state_cstar3()); %[output:group:16ecb7c6] %[output:6744c410]
fprintf('predicted_probability_cstar1/3 %.3f / %.3f\n', ... %[output:group:3633ab04] %[output:7f99534b]
    coin.predicted_probability_cstar1(), coin.predicted_probability_cstar3()); %[output:group:3633ab04] %[output:7f99534b]
fprintf('kalman_gain_cstar1/2 ......... %.3f / %.3f\n', ... %[output:group:505ff18f] %[output:3940e2cf]
    coin.kalman_gain_cstar1(), coin.kalman_gain_cstar2()); %[output:group:505ff18f] %[output:3940e2cf]

% Transition / cue / stationary distributions over contexts.
ltp = coin.local_transition_probabilities();
lcp = coin.local_cue_probabilities();
scp = coin.stationary_context_probabilities();
gtp = coin.global_transition_probabilities();
gcp = coin.global_cue_probabilities();
fprintf('local_transition_probabilities  %d-by-%d (rows sum to 1: %d)\n', ... %[output:group:8cd136f9] %[output:48d6c23a]
    size(ltp, 1), size(ltp, 2), all(abs(sum(ltp, 2) - 1) < 1e-9)); %[output:group:8cd136f9] %[output:48d6c23a]
fprintf('local_cue_probabilities ...... %d-by-%d (rows sum to 1: %d)\n', ... %[output:group:9e5ec10a] %[output:89fded59]
    size(lcp, 1), size(lcp, 2), all(abs(sum(lcp, 2) - 1) < 1e-9)); %[output:group:9e5ec10a] %[output:89fded59]
fprintf('stationary_context_probabilities [%s] (sum %.3f)\n', num2str(scp, '%.3f '), sum(scp)); %[output:072692de]
fprintf('global_transition_probabilities  [%s] (sum %.3f)\n', num2str(gtp, '%.2f '), sum(gtp)); %[output:0de2ceac]
fprintf('global_cue_probabilities ..... [%s] (sum %.3f)\n', num2str(gcp, '%.2f '), sum(gcp)); %[output:18dad861]
assert(all(abs(sum(ltp, 2) - 1) < 1e-9), 'local transition rows must sum to 1');
assert(abs(sum(scp) - 1) < 1e-9, 'stationary distribution must sum to 1');

fprintf('=======================================================\n'); %[output:4049552e]

% Per-context parameter densities (scalar-dynamics only): retention, drift, bias.
rGrid = linspace(0.80, 1.00, 201);
dGrid = linspace(-0.06, 0.06, 201);
bGrid = linspace(-0.80, 0.80, 201);
coinviz.densityLines(rGrid, coin.retention_given_context_probability(rGrid), ... %[output:group:5802d67e] %[output:55b95854]
    'FigName', 'Scalar: retention | context', ... %[output:55b95854]
    'Title', 'retention\_given\_context\_probability', 'XLabel', 'Retention a'); %[output:group:5802d67e] %[output:55b95854]
coinviz.densityLines(dGrid, coin.drift_given_context_probability(dGrid), ... %[output:group:41d962e9] %[output:5af72eda]
    'FigName', 'Scalar: drift | context', ... %[output:5af72eda]
    'Title', 'drift\_given\_context\_probability', 'XLabel', 'Drift d'); %[output:group:41d962e9] %[output:5af72eda]
coinviz.densityLines(bGrid, coin.bias_given_context_probability(bGrid), ... %[output:group:343e3ff1] %[output:3a5bd7e4]
    'FigName', 'Scalar: bias | context', ... %[output:3a5bd7e4]
    'Title', 'bias\_given\_context\_probability', 'XLabel', 'Bias'); %[output:group:343e3ff1] %[output:3a5bd7e4]
% Marginal (across-context) bias density.
figure('Name', 'Scalar: marginal bias density'); %[output:858abe8d]
plot(bGrid, coin.bias_probability(bGrid), 'LineWidth', 1.4); %[output:858abe8d]
xlabel('Bias'); ylabel('Density'); title('bias\_probability (marginal)'); %[output:858abe8d]
%%
%[text] ## Section 7 - Explicit vs implicit decomposition (c\* traces)
%[text] The COIN adaptation curve can be read out in several ways. explicit\_component is the state of the single most-responsible context (== state\_cstar1); implicit\_component is the motor output minus the average state; and the c\* traces track the most-probable context's state under different timing conventions. Here we record them through a perturbation that flips sign.
rng(7);
coin = RealTimeCOIN('infer_bias', true);
perturb = [zeros(1, 10), 0.3 * ones(1, 20), -0.3 * ones(1, 20), zeros(1, 10)];
T = numel(perturb);
mo = zeros(1, T); ex = zeros(1, T); im = zeros(1, T);
cs1 = zeros(1, T); cs2 = zeros(1, T); cs3 = zeros(1, T);
for t = 1:T
    coin.observe_y(perturb(t) + coin.sigma_sensory_noise * randn);
    mo(t)  = coin.motor_output();
    ex(t)  = coin.explicit_component();
    im(t)  = coin.implicit_component();
    cs1(t) = coin.state_cstar1();
    cs2(t) = coin.state_cstar2();
    cs3(t) = coin.state_cstar3();
end
blockEdges = [10 30 50];
cols = coinviz.palette(4);
figure('Name', 'Scalar: explicit / implicit read-outs'); %[output:6fc74164]
hold on; %[output:6fc74164]
plot(1:T, perturb, 'k--', 'LineWidth', 1.2); %[output:6fc74164]
plot(1:T, mo, 'Color', cols(1, :), 'LineWidth', 1.6); %[output:6fc74164]
plot(1:T, ex, 'Color', cols(2, :), 'LineWidth', 1.4); %[output:6fc74164]
plot(1:T, im, 'Color', cols(3, :), 'LineWidth', 1.4); %[output:6fc74164]
for e = blockEdges, xline(e, 'Color', [0.5 0.5 0.5 0.4]); end %[output:6fc74164]
xlabel('Trial'); ylabel('Adaptation'); %[output:6fc74164]
title('motor\_output, explicit\_component and implicit\_component'); %[output:6fc74164]
legend({'perturbation', 'motor\_output', 'explicit', 'implicit'}, 'Location', 'best'); %[output:6fc74164]
% The c* state estimates all track the dominant context's state.
figure('Name', 'Scalar: c* state estimates'); %[output:8022d532]
hold on; %[output:8022d532]
plot(1:T, perturb, 'k--', 'LineWidth', 1.2); %[output:8022d532]
plot(1:T, cs1, 'Color', cols(1, :), 'LineWidth', 1.4); %[output:8022d532]
plot(1:T, cs2, 'Color', cols(2, :), 'LineWidth', 1.4); %[output:8022d532]
plot(1:T, cs3, 'Color', cols(3, :), 'LineWidth', 1.4); %[output:8022d532]
for e = blockEdges, xline(e, 'Color', [0.5 0.5 0.5 0.4]); end %[output:8022d532]
xlabel('Trial'); ylabel('State estimate'); %[output:8022d532]
title('state\_cstar1 / state\_cstar2 / state\_cstar3'); %[output:8022d532]
legend({'perturbation', 'cstar1', 'cstar2', 'cstar3'}, 'Location', 'best'); %[output:8022d532]
% explicit_component is exactly state_cstar1 by construction.
assert(max(abs(ex - cs1)) < 1e-9, 'explicit_component == state_cstar1');
fprintf('Section 7: max|explicit - state_cstar1| = %.2e\n', max(abs(ex - cs1))); %[output:021c4227]
%%
%[text] ## Section 8 - Prior / hyperparameter exploration
%[text] The same feedback stream shown to two differently-tuned models: an "eager" prior (small alpha\_context, large rho\_context) that instantiates new contexts readily, versus a "sticky" prior that resists switching. We compare context creation and the c\* state read-out. The last (grey) bar is the novel context.
rng(8);
perturb = [zeros(1, 8), 0.4 * ones(1, 16), -0.4 * ones(1, 16)];
T = numel(perturb);
fb = perturb + 0.03 * randn(1, T);          % identical feedback both models see

eager  = RealTimeCOIN('alpha_context', 2,  'rho_context', 0.6);
sticky = RealTimeCOIN('alpha_context', 30, 'rho_context', 0.05);
prevE = zeros(T, eager.max_contexts + 1);
prevS = zeros(T, sticky.max_contexts + 1);
csE = zeros(1, T); csS = zeros(1, T);
for t = 1:T
    eager.observe_y(fb(t));
    sticky.observe_y(fb(t));
    prevE(t, :) = eager.predicted_context_probabilities();
    prevS(t, :) = sticky.predicted_context_probabilities();
    csE(t) = eager.state_cstar1();
    csS(t) = sticky.state_cstar1();
end
coinviz.contextBars(prevE, [], 'FigName', 'Eager prior: context creation', ... %[output:group:640a475b] %[output:9f29f62b]
    'NovelContext', true, 'PrevTitle', 'Eager: predicted context probabilities'); %[output:group:640a475b] %[output:9f29f62b]
coinviz.contextBars(prevS, [], 'FigName', 'Sticky prior: context creation', ... %[output:group:0ad0024b] %[output:023dced4]
    'NovelContext', true, 'PrevTitle', 'Sticky: predicted context probabilities'); %[output:group:0ad0024b] %[output:023dced4]
figure('Name', 'Prior comparison: c*1 state'); %[output:24b88fc2]
hold on; %[output:24b88fc2]
plot(1:T, fb, 'x', 'Color', [0.7 0.7 0.7], 'MarkerSize', 4); %[output:24b88fc2]
plot(1:T, csE, 'Color', cols(1, :), 'LineWidth', 1.5); %[output:24b88fc2]
plot(1:T, csS, 'Color', cols(2, :), 'LineWidth', 1.5); %[output:24b88fc2]
xlabel('Trial'); ylabel('state\_cstar1'); %[output:24b88fc2]
legend({'feedback', 'eager', 'sticky'}, 'Location', 'best'); %[output:24b88fc2]
title('Prior effect on the dominant-context state'); %[output:24b88fc2]
fprintf('Eager model contexts: %d;  Sticky model contexts: %d\n', ... %[output:group:48d9c0c8] %[output:4399b5ec]
    eager.diagnostics().C, sticky.diagnostics().C); %[output:group:48d9c0c8] %[output:4399b5ec]
%%
%[text] ## Section 9 - State|context probability evolution (composite heat-map)
%[text] Each trial we evaluate state\_given\_context\_probability on a fixed grid and stack the columns into one image. Every context is tinted its own colour and the densities are additively blended, so you can watch contexts claim regions of state space as the contingency changes; the novel context is grey. Below the figure we print every inferred per-context parameter.
rng(9);
coin = RealTimeCOIN('infer_bias', true);
perturb = [0.20 * ones(1, 15), -0.35 * ones(1, 15), 0.20 * ones(1, 15)];
cues    = [ones(1, 15), 2 * ones(1, 15), ones(1, 15)];
T = numel(perturb);
sGrid = linspace(-0.8, 0.8, 161);
recorded = containers.Map('KeyType', 'double', 'ValueType', 'any');
novelDens = zeros(numel(sGrid), T);
trueLine = zeros(1, T);
for t = 1:T
    coin.observe_q(cues(t));
    coin.observe_y(perturb(t) + coin.sigma_sensory_noise * randn);
    dmap = coin.state_given_context_probability(sGrid);
    for kk = cell2mat(dmap.keys)
        if ~isKey(recorded, kk)
            recorded(kk) = zeros(numel(sGrid), T);
        end
        col = recorded(kk); col(:, t) = dmap(kk)'; recorded(kk) = col;
    end
    novelDens(:, t) = coin.novel_state_probability(sGrid)';
    trueLine(t) = perturb(t);
end
coinviz.contextDensityEvolution(1:T, sGrid, recorded, ... %[output:group:0aac1bd9] %[output:92213e6b]
    'FigName', 'Scalar: state|context evolution', ... %[output:92213e6b]
    'Title', 'state\_given\_context\_probability over trials (colours = contexts)', ... %[output:92213e6b]
    'NovelDens', novelDens, 'TrueLine', trueLine, 'BlockEdges', [15 30]); %[output:group:0aac1bd9] %[output:92213e6b]
% Diagnostics: every inferred per-context parameter.
D = coin.diagnostics();
fprintf('\nInferred contexts (K = %d):\n', D.C); %[output:75e964fb]
for c = 1:D.C %[output:group:6dd1d2b3]
    fprintf('  ctx %d: retention %.3f  drift % .4f  bias % .3f  state_mean % .3f\n', ... %[output:4c0f2e66]
        c, D.retention(c), D.drift(c), D.bias(c), D.state_mean(c)); %[output:4c0f2e66]
end %[output:group:6dd1d2b3]

